  onComplete: (userId: string) => void;
  lang: Language;
  t: any;
  platform: Platform;
}

const SettingsView: React.FC<SettingsViewProps> = ({ onComplete, lang, t, platform }) => {
  const [copied, setCopied] = useState(false);
  const [userId, setUserId] = useState('');
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [profilePreviewUrl, setProfilePreviewUrl] = useState<string | null>(null);
  const [errors, setErrors] = useState<{ userId?: boolean; screenshot?: boolean; profileScreenshot?: boolean; userIdLength?: boolean }>({});
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [overallProgress, setOverallProgress] = useState(0);
  const [statusText, setStatusText] = useState("UPLINKING...");

  const platformName = platform === '1xbet' ? '1xBet' : 'Linebet';
  const platformImg = platform === '1xbet' 
    ? 'https://image2url.com/images/1766063900504-6b7a7a95-66e6-42e3-b560-3e6cb897acf3.jpeg' 
    : 'https://image2url.com/images/1766063887850-97673d7d-b0b6-491f-872a-4fd7b71d4a72.jpeg';

  const linebetDownloadUrl = "https://lb-aff.com//L?tag=d_3386416m_66803c_apk1&site=3386416&ad=66803";
  const xbetDownloadUrl = "https://reffpa.com/L?tag=d_2845435m_27409c_&site=2845435&ad=27409";

  const [verificationSteps, setVerificationSteps] = useState([
    { id: 'server', label: t.step_server, status: "pending", icon: Server },
    { id: 'deposit', label: t.step_receipt, status: "pending", icon: Database },
    { id: 'id', label: t.step_validating, status: "pending", icon: Fingerprint }
  ]);

  const handleCopy = () => {
    audioManager.playCopy();
    navigator.clipboard.writeText("KAJO117");
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const url = URL.createObjectURL(e.target.files[0]);
      setPreviewUrl(url);
      setErrors(prev => ({ ...prev, screenshot: false }));
    }
  };

  const handleProfileFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const url = URL.createObjectURL(e.target.files[0]);
      setProfilePreviewUrl(url);
      setErrors(prev => ({ ...prev, profileScreenshot: false }));
    }
  };

  const handleUserIdChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = e.target.value.replace(/[^0-9]/g, '');
    if (val.length <= 15) {
        setUserId(val);
        if (val.length >= 10) {
             setErrors(prev => ({ ...prev, userId: false, userIdLength: false }));
        }
    }
  };

  const validateAndSubmit = () => {
    audioManager.playClick();
    const trimmedId = userId.trim();
    const isLengthValid = trimmedId.length >= 10 && trimmedId.length <= 15;

    const newErrors = {
      userId: !trimmedId,
      userIdLength: !isLengthValid,
      screenshot: !previewUrl,
      profileScreenshot: !profilePreviewUrl
    };

    setErrors(newErrors);

    if (!newErrors.userId && !newErrors.userIdLength && !newErrors.screenshot && !newErrors.profileScreenshot) {
      setIsSubmitting(true);

      const updateStep = (index: number, status: string) => {
        setVerificationSteps(prev => 
          prev.map((step, i) => i === index ? { ...step, status } : step)
        );
      };

      updateStep(0, "active");
      setStatusText("SYSTEM UPLINK...");

      const duration = 4500;
      const interval = 30;
      const totalSteps = duration / interval;
      const increment = 100 / totalSteps;

      const timer = setInterval(() => {
        setOverallProgress(prev => {
            const next = prev + increment;
            if (next >= 33 && next < 66 && verificationSteps[0].status !== 'completed') {
                updateStep(0, "completed");
                updateStep(1, "active");
                setStatusText("VERIFYING DEPOSIT...");
            }
            if (next >= 66 && next < 95 && verificationSteps[1].status !== 'completed') {
                updateStep(1, "completed");
                updateStep(2, "active");
                setStatusText("VERIFYING ID...");
            }
            if (next >= 100) {
                updateStep(2, "completed");
                setStatusText("AUTHENTICATED");
                clearInterval(timer);
                return 100;
            }
            return next;
        });
      }, interval);

      setTimeout(() => {
        onComplete(trimmedId);
      }, duration + 800);
    }
  };

  return (
    <div className="flex flex-col h-full px-5 pt-6 pb-24 overflow-y-auto custom-scrollbar relative bg-black">
