        setDisplayMultiplier((1.00 + Math.random() * 1.8).toFixed(2));
    }, 70);

    try {
        // Firebase Realtime Database REST API URL
        const DB_URL = `https://crazy-vip-f0d57-default-rtdb.firebaseio.com/users/${cleanId}.json`;
        const SIGNAL_URL = `https://crazy-vip-f0d57-default-rtdb.firebaseio.com/signal.json`;

        const userResponse = await fetch(DB_URL);
        const userData = await userResponse.json();

        // Check if user exists and is active in the system
        if (!userData || !userData.active) {
            // Artificial delay for realism
            await new Promise(resolve => setTimeout(resolve, 2000));

            if (loadingIntervalRef.current) {
                clearInterval(loadingIntervalRef.current);
                loadingIntervalRef.current = null;
            }
            setLoading(false);
            setDisplayMultiplier("1.00");
            audioManager.playError();
            return;
        }

        // Fetch the current server-side signal
        const signalResponse = await fetch(SIGNAL_URL);
