              </div>
              <span className="text-xs font-mono text-green-500 font-bold uppercase tracking-widest">{t.system_active}</span>
           </div>
        </div>

        <div className="flex items-center gap-2 bg-zinc-900/50 px-3 py-1 rounded-md border border-zinc-800">
            <User className="w-3.5 h-3.5 text-zinc-500" />
