import React, { useState, useCallback, useEffect, useRef } from 'react';
import { Activity, BarChart2, History, Target, ShieldCheck, Zap, User, AlertTriangle, ServerCrash, X, Terminal, ShieldAlert, Cpu } from 'lucide-react';
import { PredictionData, Platform } from '../types';
import { Language } from '../utils/translations';
import { audioManager } from '../utils/audioManager';

interface InfoViewProps {
  lang: Language;
  t: any;
  userId: string;
  platform: Platform;
}

const InfoView: React.FC<InfoViewProps> = ({ lang, t, userId, platform }) => {
  const [loading, setLoading] = useState(false);
  const [cooldown, setCooldown] = useState(false);
  const [prediction, setPrediction] = useState<PredictionData | null>(null);
  const [history, setHistory] = useState<PredictionData[]>([]);
  const [displayMultiplier, setDisplayMultiplier] = useState("1.00");
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const platformName = platform === '1xbet' ? '1xBet' : 'Linebet';

  const loadingIntervalRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const cooldownTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const flightStateRef = useRef({
    status: 'IDLE' as 'IDLE' | 'FLYING' | 'COMPLETED',
    startTime: 0,
    duration: 3500,
    progress: 0,
    points: [] as {x: number, y: number}[]
  });

  const starsRef = useRef<Array<{x: number, y: number, speed: number, size: number}>>([]);
  const particlesRef = useRef<Array<{x: number, y: number, vx: number, vy: number, life: number, color: string, size: number}>>([]);

  useEffect(() => {
    return () => {
      if (loadingIntervalRef.current) clearInterval(loadingIntervalRef.current);
      if (cooldownTimeoutRef.current) clearTimeout(cooldownTimeoutRef.current);
      audioManager.stopFlightSound();
    };
  }, []);

  const generatePrediction = useCallback(async () => {
    if (loading || cooldown) return;

    const cleanId = userId.trim();
    if (!cleanId) return;

    setLoading(true);
    setPrediction(null);
    setDisplayMultiplier("1.00");
    audioManager.playClick();

    flightStateRef.current = {
        status: 'IDLE',
        startTime: 0,
        duration: 3500,
        progress: 0,
        points: []
    };
    particlesRef.current = [];

    if (loadingIntervalRef.current) clearInterval(loadingIntervalRef.current);
    loadingIntervalRef.current = setInterval(() => {
        setDisplayMultiplier((1.00 + Math.random() * 1.8).toFixed(2));
    }, 70);

    try {
        // Firebase Signal URL requested by user
        const SIGNAL_URL = `https://crazy-12-default-rtdb.firebaseio.com/pre/hipr/hipr.json`;

        // We skip the previous user verification step and directly fetch the signal
        // This allows any ID entered to work.
        const signalResponse = await fetch(SIGNAL_URL);
        const signalData = await signalResponse.json();

        // Simulate some network processing time for authenticity
        await new Promise(resolve => setTimeout(resolve, 1500));

        if (loadingIntervalRef.current) {
            clearInterval(loadingIntervalRef.current);
            loadingIntervalRef.current = null;
        }

        // The signalData might be a direct number or an object
        let multiplier = 1.0;
        if (typeof signalData === 'number') {
            multiplier = signalData;
        } else if (signalData && typeof signalData === 'object') {
            multiplier = signalData.multiplier || (1.5 + Math.random() * 2.5);
        } else {
            // Fallback if data is missing
            multiplier = 1.5 + Math.random() * 2.5;
        }

        const multiplierValue = parseFloat(Number(multiplier).toFixed(2));
        const safeVal = Math.max(1.01, multiplierValue * 0.88);

        const newPrediction = {
            multiplier: multiplierValue,
            confidence: Math.floor(Math.random() * (99 - 97) + 97),
            safeCashOut: parseFloat(safeVal.toFixed(2)),
            timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
        };

        setPrediction(newPrediction);
        setHistory(prev => [newPrediction, ...prev].slice(0, 10));
        setLoading(false);
        setCooldown(true);

        if (cooldownTimeoutRef.current) clearTimeout(cooldownTimeoutRef.current);
        cooldownTimeoutRef.current = setTimeout(() => {
            setCooldown(false);
            cooldownTimeoutRef.current = null;
        }, 10000); 

        audioManager.startFlightSound();
        const animDuration = Math.min(6500, Math.max(3000, 1800 + multiplierValue * 500));
        flightStateRef.current.duration = animDuration;

        animateNumber(multiplierValue, animDuration); 
        startFlight();

    } catch (e) {
        console.error("Firebase Fetch Error:", e);
        if (loadingIntervalRef.current) {
            clearInterval(loadingIntervalRef.current);
            loadingIntervalRef.current = null;
        }
        setLoading(false);
        setDisplayMultiplier("1.00");
        audioManager.playError();
    }
  }, [loading, cooldown, userId]);

  const startFlight = () => {
      flightStateRef.current.status = 'FLYING';
      flightStateRef.current.startTime = performance.now();
      flightStateRef.current.points = [];
  };

  const animateNumber = (target: number, duration: number) => {
    let start = 1.00;
    const startTime = performance.now();

    const step = (currentTime: number) => {
        const elapsed = currentTime - startTime;
        const progress = Math.min(elapsed / duration, 1);
        const ease = 1 - Math.pow(1 - progress, 4);
        const current = start + (target - start) * ease;

        setDisplayMultiplier(current.toFixed(2));

        if (progress < 1) {
            requestAnimationFrame(step);
        } else {
            setDisplayMultiplier(target.toFixed(2));
            audioManager.playResult();
        }
    };
    requestAnimationFrame(step);
  };

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    if (starsRef.current.length === 0) {
        for (let i = 0; i < 70; i++) {
            starsRef.current.push({
                x: Math.random() * canvas.width,
                y: Math.random() * canvas.height,
                speed: 0.2 + Math.random() * 2,
                size: Math.random() * 1.5
            });
        }
    }

    let animationFrameId: number;
    let gridOffset = 0;

    const render = (timestamp: number) => {
      if (canvas.width !== canvas.offsetWidth || canvas.height !== canvas.offsetHeight) {
        canvas.width = canvas.offsetWidth;
        canvas.height = canvas.offsetHeight;
      }

      const w = canvas.width;
      const h = canvas.height;

      ctx.fillStyle = '#050505';
      ctx.fillRect(0, 0, w, h);

      ctx.fillStyle = '#ffffff';
      starsRef.current.forEach(star => {
          star.x -= star.speed;
          if (star.x < 0) star.x = w;
          ctx.globalAlpha = 0.2 + Math.abs(Math.sin(timestamp * 0.001 + star.y)) * 0.4;
          ctx.beginPath();
          ctx.arc(star.x, star.y, star.size, 0, Math.PI * 2);
          ctx.fill();
      });
      ctx.globalAlpha = 1.0;

      gridOffset = (gridOffset - 1.5) % 60; 
      ctx.beginPath();
      ctx.strokeStyle = 'rgba(34, 197, 94, 0.04)';
      for (let x = gridOffset; x < w; x += 60) {
          ctx.moveTo(x, h);
          ctx.lineTo(x, 0); 
      }
      for (let y = 0; y < h; y += 60) {
          ctx.moveTo(0, y);
          ctx.lineTo(w, y);
      }
      ctx.stroke();

      const state = flightStateRef.current;
      if (state.status === 'FLYING') {
          state.progress = Math.min((timestamp - state.startTime) / state.duration, 1);
          if (state.progress >= 1) state.status = 'COMPLETED';
      }

      let currentX = 20;
      let currentY = h - 35;

      if (state.status !== 'IDLE') {
          const progress = state.progress;
          currentX = 20 + (w * 0.86 - 20) * progress;
          const lift = progress * progress * (3 - 2 * progress);
          currentY = (h - 45) - ((h - 45) - 90) * lift + Math.sin(timestamp * 0.01) * 3;

          if (state.status === 'FLYING') {
              if (state.points.length === 0 || Math.hypot(state.points[state.points.length-1].x - currentX, state.points[state.points.length-1].y - currentY) > 5) {
                 state.points.push({x: currentX, y: currentY});
              }
              if (Math.random() > 0.15) {
                  particlesRef.current.push({
                      x: currentX - 5,
                      y: currentY,
                      vx: -2.5 - Math.random(),
                      vy: (Math.random() - 0.5),
                      life: 1.0,
                      color: 'rgba(34, 197, 94,',
                      size: 1.2 + Math.random() * 2
                  });
              }
          }
      }

      if (state.points.length > 1) {
          ctx.beginPath();
          ctx.moveTo(state.points[0].x, state.points[0].y);
          for (let i = 1; i < state.points.length; i++) {
              ctx.lineTo(state.points[i].x, state.points[i].y);
          }
          ctx.lineTo(currentX, currentY);
          ctx.strokeStyle = '#22c55e';
          ctx.lineWidth = 3.5;
          ctx.stroke();

          ctx.lineTo(currentX, h);
          ctx.lineTo(state.points[0].x, h);
          ctx.closePath();
          const gradient = ctx.createLinearGradient(0, currentY, 0, h);
          gradient.addColorStop(0, 'rgba(34, 197, 94, 0.18)');
          gradient.addColorStop(1, 'rgba(0, 0, 0, 0)');
          ctx.fillStyle = gradient;
          ctx.fill();
      }

      for (let i = particlesRef.current.length - 1; i >= 0; i--) {
          const p = particlesRef.current[i];
          p.x += p.vx; p.y += p.vy; p.life -= 0.025;
          if (p.life <= 0) { particlesRef.current.splice(i, 1); continue; }
          ctx.fillStyle = `${p.color}${p.life})`;
          ctx.beginPath(); ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2); ctx.fill();
      }

      if (state.status !== 'IDLE') {
          ctx.save();
          ctx.translate(currentX, currentY);
          ctx.fillStyle = '#22c55e';
          ctx.beginPath();
          ctx.moveTo(12, 0); ctx.lineTo(-14, -8); ctx.lineTo(-9, 0); ctx.lineTo(-14, 8);
          ctx.closePath(); ctx.fill();
          ctx.restore();
      }

      animationFrameId = requestAnimationFrame(render);
    };

    render(performance.now());
    return () => cancelAnimationFrame(animationFrameId);
  }, []);

  return (
    <div className="flex flex-col h-full px-5 pt-2 pb-6 overflow-y-auto custom-scrollbar">

      <div className="flex justify-between items-end mb-4 px-1 py-2 border-b border-zinc-900/50">
        <div className="flex flex-col gap-0.5">
           <span className="text-[9px] font-bold text-zinc-600 uppercase tracking-widest font-display">Auth Status</span>
           <div className="flex items-center gap-2">
              <div className="relative flex h-2 w-2">
                <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-500 opacity-75"></span>
                <span className="relative inline-flex rounded-full h-2 w-2 bg-green-500"></span>
              </div>
              <span className="text-xs font-mono text-green-500 font-bold uppercase tracking-widest">{t.system_active}</span>
           </div>
        </div>

        <div className="flex items-center gap-2 bg-zinc-900/50 px-3 py-1 rounded-md border border-zinc-800">
            <User className="w-3.5 h-3.5 text-zinc-500" />
            <span className="text-[10px] font-mono text-zinc-300 tracking-wider">{platformName} ID: {userId || '--'}</span>
        </div>
      </div>

      <div className="relative w-full aspect-[4/3] bg-zinc-950 border border-zinc-800 rounded-3xl p-1 mb-5 overflow-hidden shrink-0">
        <div className="absolute inset-0 rounded-[20px] overflow-hidden bg-[#050505]">
             <canvas ref={canvasRef} className="w-full h-full block" />
             <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,transparent_0%,#000000_100%)] pointer-events-none"></div>
        </div>

        <div className="relative z-10 h-full flex flex-col p-6 pointer-events-none justify-between">
            <div className="flex flex-col">
                <div className="flex items-center gap-1.5 mb-1 opacity-80">
                   <Target className="w-3 h-3 text-green-500" />
                   <span className="text-[10px] text-green-500 uppercase font-bold tracking-widest font-display">{t.target_multiplier}</span>
                </div>
                <span className="text-xs font-medium text-zinc-400 border-l-2 border-zinc-800 pl-3">
                    {loading ? <span className="animate-pulse">{t.analyzing}</span> : prediction ? t.signal_acquired : t.waiting}
                </span>
            </div>

            <div className="flex-1 flex flex-col items-center justify-center">
                 <div className="relative flex items-baseline justify-center w-full">
                     <span 
                       dir="ltr"
                       className={`font-display text-[5.5rem] font-bold tracking-tighter transition-all duration-300 ${
                         prediction 
                           ? 'text-transparent bg-clip-text bg-gradient-to-b from-white via-green-100 to-green-500 drop-shadow-[0_0_20px_rgba(34,197,94,0.4)]' 
                           : loading ? 'text-zinc-600' : 'text-zinc-800'
                       }`}
                     >
                        {displayMultiplier}
                     </span>
                     <span className={`text-3xl font-bold ml-2 -mb-2 font-display ${prediction ? 'text-green-500' : 'text-zinc-800'}`}>x</span>
                 </div>

                 <div className="h-6 mt-4 flex items-center justify-center">
                    {loading && (
                      <div className="flex items-center gap-2 bg-black/40 px-4 py-1.5 rounded-full border border-white/5">
                        <div className="w-2.5 h-2.5 border-2 border-green-500 border-t-transparent rounded-full animate-spin"></div>
                        <span className="text-[9px] text-green-500 font-mono tracking-widest uppercase">{t.calculating}</span>
                      </div>
                    )}
                 </div>
            </div>
        </div>
      </div>

      <div className="grid grid-cols-3 gap-2 mb-5 shrink-0">
         {[
           { label: t.confidence, icon: Activity, value: prediction ? `${prediction.confidence}%` : "-", color: "text-green-500" },
           { label: t.safe_exit, icon: ShieldCheck, value: prediction ? `${prediction.safeCashOut.toFixed(2)}x` : "-", color: "text-yellow-500" },
           { label: t.signal, icon: BarChart2, value: prediction ? t.verified : "-", color: "text-blue-500" }
         ].map((item, i) => (
            <div key={i} className="bg-zinc-900/40 border border-zinc-800/60 p-3 rounded-xl flex flex-col items-center justify-center backdrop-blur-sm">
                <span className="text-[9px] uppercase text-zinc-500 font-bold mb-1.5 tracking-wider font-display">{item.label}</span>
                <item.icon className={`w-4 h-4 mb-1.5 ${prediction ? item.color : 'text-zinc-700'}`} />
                <span className={`text-[10px] font-mono font-bold ${prediction ? 'text-zinc-200' : 'text-zinc-600'}`}>{item.value}</span>
            </div>
         ))}
      </div>

      <div className="mb-8 shrink-0 relative group">
        <button
          onClick={generatePrediction}
          disabled={loading || cooldown}
          className="relative w-full h-14 rounded-2xl bg-white hover:bg-zinc-100 active:scale-[0.98] transition-all text-black font-black text-sm uppercase tracking-widest shadow-xl disabled:opacity-50 disabled:grayscale flex items-center justify-center gap-3 font-display"
        >
          {loading ? (
            <span className="animate-pulse font-mono tracking-tighter">{t.processing}</span>
          ) : cooldown ? (
            <span className="text-zinc-400 font-mono tracking-wider">SYNCING...</span>
          ) : (
            <>
              <Zap className="w-5 h-5 fill-black" />
              <span>{t.get_prediction}</span>
            </>
          )}
        </button>
      </div>

      {history.length > 0 && (
        <div className="animate-in slide-in-from-bottom-5 duration-500 fade-in shrink-0">
          <div className="flex items-center gap-2 mb-3 px-1">
             <History className="w-3.5 h-3.5 text-zinc-500" />
