             <div className="h-px flex-1 bg-zinc-900 ml-2"></div>
          </div>

          <div className="grid grid-cols-5 gap-2" dir="ltr">
            {history.slice(0, 5).map((item, idx) => (
               <div key={idx} className="flex flex-col items-center justify-center p-2 rounded-lg bg-zinc-900/50 border border-zinc-800/50 hover:bg-zinc-900 transition-colors">
                  <span className={`text-xs font-mono font-bold ${item.multiplier >= 2.0 ? 'text-green-500' : 'text-blue-500'}`}>
                    {item.multiplier.toFixed(2)}x
                  </span>
                  <span className="text-[8px] text-zinc-600 font-mono mt-0.5 opacity-60">{item.timestamp}</span>
               </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
