import React, { useState, useCallback, useEffect, useRef } from 'react';
import { Activity, BarChart2, History, Target, ShieldCheck, Zap, User, AlertTriangle, ServerCrash, X, Terminal, ShieldAlert, Cpu } from 'lucide-react';
import { PredictionData, Platform } from '../types';
