                      y: currentY,
                      vx: -2.5 - Math.random(),
                      vy: (Math.random() - 0.5),
                      life: 1.0,
                      color: 'rgba(34, 197, 94,',
                      size: 1.2 + Math.random() * 2
                  });
              }
          }
