import React, { useState, useCallback, useEffect, useRef } from 'react';
import { Activity, BarChart2, History, Target, ShieldCheck, Zap, User, Clock, Shield } from 'lucide-react';
import { PredictionData, Platform } from '../types';
import { Language } from '../utils/translations';
import { audioManager } from '../utils/audioManager';

interface InfoViewProps {
  lang: Language;
  t: any;
  userId: string;
  platform: Platform;
}

const InfoView: React.FC<InfoViewProps> = ({ lang, t, userId, platform }) => {
  const [loading, setLoading] = useState(false);
  const [cooldown, setCooldown] = useState(false);
  const [prediction, setPrediction] = useState<PredictionData | null>(null);
  const [history, setHistory] = useState<PredictionData[]>([]);
  const [displayMultiplier, setDisplayMultiplier] = useState("1.00");
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const platformName = platform === '1xbet' ? '1xBet' : 'Linebet';

  const loadingIntervalRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const cooldownTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const flightStateRef = useRef({
    status: 'IDLE' as 'IDLE' | 'FLYING' | 'COMPLETED',
    startTime: 0,
    duration: 3500,
    progress: 0,
    points: [] as {x: number, y: number}[]
  });

  const starsRef = useRef<Array<{x: number, y: number, speed: number, size: number}>>([]);
  const particlesRef = useRef<Array<{x: number, y: number, vx: number, vy: number, life: number, color: string, size: number}>>([]);

  useEffect(() => {
    return () => {
      if (loadingIntervalRef.current) clearInterval(loadingIntervalRef.current);
      if (cooldownTimeoutRef.current) clearTimeout(cooldownTimeoutRef.current);
      audioManager.stopFlightSound();
    };
  }, []);

  const generatePrediction = useCallback(async () => {
    if (loading || cooldown) return;

    // Any ID entered by the user is accepted without strict verification
    setLoading(true);
    setPrediction(null);
    setDisplayMultiplier("1.00");
    audioManager.playClick();

    flightStateRef.current = {
        status: 'IDLE',
        startTime: 0,
        duration: 3500,
        progress: 0,
        points: []
    };
    particlesRef.current = [];

    // Visual feedback: rapid number cycling while establishing connection
    if (loadingIntervalRef.current) clearInterval(loadingIntervalRef.current);
    loadingIntervalRef.current = setInterval(() => {
        setDisplayMultiplier((1.00 + Math.random() * 2.8).toFixed(2));
    }, 60);

    try {
        // Targeted Firebase REST API Path: pre/hipr/hipr
        const DB_URL = `https://crazy-12-default-rtdb.firebaseio.com/pre/hipr/hipr.json`;

        const response = await fetch(DB_URL);
        if (!response.ok) throw new Error("Database Uplink Failed");

        const data = await response.json();

        // Authentic processing delay for high-end feel
        await new Promise(resolve => setTimeout(resolve, 2000));

        if (loadingIntervalRef.current) {
            clearInterval(loadingIntervalRef.current);
            loadingIntervalRef.current = null;
        }

        /**
         * Robust Multiplier Extraction:
         * 1. Check if data is a direct number (odd).
         * 2. Check for common keys: 'odd', 'multiplier', 'val'.
         * 3. Fallback to a random simulated value if unreachable.
         */
        let rawVal = 0;
        if (typeof data === 'number') {
            rawVal = data;
        } else if (data && typeof data === 'object') {
            rawVal = data.odd || data.multiplier || data.val || (1.6 + Math.random() * 3.4);
        } else {
            rawVal = 1.75 + Math.random() * 2.25; 
        }

        const multiplierValue = parseFloat(Number(rawVal).toFixed(2));
        // Safe exit is calculated as ~12-15% below the expected crash point
        const safeVal = Math.max(1.01, multiplierValue * 0.86);

        const newPrediction = {
            multiplier: multiplierValue,
            confidence: Math.floor(Math.random() * (99 - 96) + 96),
            safeCashOut: parseFloat(safeVal.toFixed(2)),
            timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' }),
        };

        setPrediction(newPrediction);
        setHistory(prev => [newPrediction, ...prev].slice(0, 10));
        setLoading(false);
        setCooldown(true);

        // Security cooldown to prevent rapid-fire requests
        if (cooldownTimeoutRef.current) clearTimeout(cooldownTimeoutRef.current);
        cooldownTimeoutRef.current = setTimeout(() => {
            setCooldown(false);
            cooldownTimeoutRef.current = null;
        }, 8000); 

        audioManager.startFlightSound();
        const animDuration = Math.min(7000, Math.max(2800, 1600 + multiplierValue * 480));
        flightStateRef.current.duration = animDuration;

        animateNumber(multiplierValue, animDuration); 
        startFlight();

    } catch (e) {
        console.error("Critical System Error:", e);
        if (loadingIntervalRef.current) {
            clearInterval(loadingIntervalRef.current);
            loadingIntervalRef.current = null;
        }
        setLoading(false);
        setDisplayMultiplier("1.00");
        audioManager.playError();
    }
  }, [loading, cooldown]);

  const startFlight = () => {
      flightStateRef.current.status = 'FLYING';
      flightStateRef.current.startTime = performance.now();
      flightStateRef.current.points = [];
  };

  const animateNumber = (target: number, duration: number) => {
    let start = 1.00;
    const startTime = performance.now();

    const step = (currentTime: number) => {
        const elapsed = currentTime - startTime;
        const progress = Math.min(elapsed / duration, 1);
        const ease = 1 - Math.pow(1 - progress, 4); // Quartic ease-out for smooth finish
        const current = start + (target - start) * ease;

        setDisplayMultiplier(current.toFixed(2));

        if (progress < 1) {
            requestAnimationFrame(step);
        } else {
            setDisplayMultiplier(target.toFixed(2));
            audioManager.playResult();
        }
    };
    requestAnimationFrame(step);
  };

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    if (starsRef.current.length === 0) {
        for (let i = 0; i < 75; i++) {
            starsRef.current.push({
                x: Math.random() * canvas.width,
                y: Math.random() * canvas.height,
                speed: 0.15 + Math.random() * 1.8,
                size: Math.random() * 1.4
            });
        }
    }

    let animationFrameId: number;
    let gridOffset = 0;

    const render = (timestamp: number) => {
      if (canvas.width !== canvas.offsetWidth || canvas.height !== canvas.offsetHeight) {
        canvas.width = canvas.offsetWidth;
        canvas.height = canvas.offsetHeight;
      }

      const w = canvas.width;
      const h = canvas.height;

      ctx.fillStyle = '#050505';
      ctx.fillRect(0, 0, w, h);

      // Deep space parallax stars
      ctx.fillStyle = '#ffffff';
      starsRef.current.forEach(star => {
          star.x -= star.speed;
          if (star.x < 0) star.x = w;
          ctx.globalAlpha = 0.2 + Math.abs(Math.sin(timestamp * 0.0007 + star.y)) * 0.5;
          ctx.beginPath(); ctx.arc(star.x, star.y, star.size, 0, Math.PI * 2); ctx.fill();
      });
      ctx.globalAlpha = 1.0;

      // Scanning HUD Grid
      gridOffset = (gridOffset - 1.4) % 60; 
      ctx.beginPath();
      ctx.strokeStyle = 'rgba(34, 197, 94, 0.04)';
      for (let x = gridOffset; x < w; x += 60) { ctx.moveTo(x, h); ctx.lineTo(x, 0); }
      for (let y = 0; y < h; y += 60) { ctx.moveTo(0, y); ctx.lineTo(w, y); }
      ctx.stroke();

      const state = flightStateRef.current;
      if (state.status === 'FLYING') {
          state.progress = Math.min((timestamp - state.startTime) / state.duration, 1);
          if (state.progress >= 1) state.status = 'COMPLETED';
      }

      let currentX = 20;
      let currentY = h - 35;

      if (state.status !== 'IDLE') {
          const progress = state.progress;
          currentX = 20 + (w * 0.88 - 20) * progress;
          const lift = progress * progress * (3 - 2 * progress); // Custom bezier curve
          currentY = (h - 45) - ((h - 45) - 90) * lift + Math.sin(timestamp * 0.01) * 3;

          if (state.status === 'FLYING') {
              if (state.points.length === 0 || Math.hypot(state.points[state.points.length-1].x - currentX, state.points[state.points.length-1].y - currentY) > 5) {
                 state.points.push({x: currentX, y: currentY});
              }
              if (Math.random() > 0.12) {
                  particlesRef.current.push({
                      x: currentX - 6,
                      y: currentY,
                      vx: -3.5 - Math.random() * 2,
                      vy: (Math.random() - 0.5) * 1.8,
                      life: 1.0,
                      color: 'rgba(34, 197, 94,',
                      size: 1 + Math.random() * 2.5
                  });
              }
          }
      }

      // Energy Trail
      if (state.points.length > 1) {
          ctx.beginPath();
          ctx.moveTo(state.points[0].x, state.points[0].y);
          for (let i = 1; i < state.points.length; i++) {
              ctx.lineTo(state.points[i].x, state.points[i].y);
          }
          ctx.lineTo(currentX, currentY);
          ctx.strokeStyle = '#22c55e';
          ctx.lineWidth = 4.5;
          ctx.stroke();

          // Under-trail volume gradient
          ctx.lineTo(currentX, h);
          ctx.lineTo(state.points[0].x, h);
          ctx.closePath();
          const gradient = ctx.createLinearGradient(0, currentY, 0, h);
          gradient.addColorStop(0, 'rgba(34, 197, 94, 0.25)');
          gradient.addColorStop(1, 'rgba(0, 0, 0, 0)');
          ctx.fillStyle = gradient;
          ctx.fill();
      }

      // Afterburner Particles
      for (let i = particlesRef.current.length - 1; i >= 0; i--) {
          const p = particlesRef.current[i];
          p.x += p.vx; p.y += p.vy; p.life -= 0.022;
          if (p.life <= 0) { particlesRef.current.splice(i, 1); continue; }
          ctx.fillStyle = `${p.color}${p.life})`;
          ctx.beginPath(); ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2); ctx.fill();
      }

      // Dynamic Rocket Graphic
      if (state.status !== 'IDLE') {
          ctx.save();
          ctx.translate(currentX, currentY);
          ctx.fillStyle = '#22c55e';
          ctx.shadowBlur = 10;
          ctx.shadowColor = 'rgba(34, 197, 94, 0.5)';
          ctx.beginPath();
          ctx.moveTo(15, 0); ctx.lineTo(-14, -10); ctx.lineTo(-9, 0); ctx.lineTo(-14, 10);
          ctx.closePath(); ctx.fill();
          ctx.restore();
      }

      animationFrameId = requestAnimationFrame(render);
    };

    render(performance.now());
    return () => cancelAnimationFrame(animationFrameId);
  }, []);

  return (
    <div className="flex flex-col h-full px-5 pt-3 pb-8 overflow-y-auto custom-scrollbar">

      <div className="flex justify-between items-end mb-5 px-1 py-3 border-b border-zinc-900/40">
        <div className="flex flex-col gap-1">
           <span className="text-[10px] font-bold text-zinc-600 uppercase tracking-widest font-display">Auth Protocol</span>
           <div className="flex items-center gap-2">
              <div className="relative flex h-2 w-2">
                <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-500 opacity-75"></span>
                <span className="relative inline-flex rounded-full h-2 w-2 bg-green-500"></span>
              </div>
              <span className="text-xs font-mono text-green-500 font-black uppercase tracking-widest">{t.system_active}</span>
           </div>
        </div>

        <div className="flex items-center gap-2 bg-zinc-900/60 px-4 py-1.5 rounded-lg border border-zinc-800">
            <User className="w-3.5 h-3.5 text-zinc-500" />
            <span className="text-[11px] font-mono text-zinc-300 tracking-wider">ID: {userId || 'GUEST'}</span>
        </div>
      </div>

      <div className="relative w-full aspect-[16/11] bg-zinc-950 border border-zinc-800/80 rounded-[2.2rem] p-1.5 mb-6 overflow-hidden shrink-0 shadow-[0_20px_50px_rgba(0,0,0,0.6)]">
        <div className="absolute inset-0 rounded-[2rem] overflow-hidden bg-[#050505]">
             <canvas ref={canvasRef} className="w-full h-full block" />
             <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,transparent_0%,#000000_100%)] pointer-events-none"></div>
        </div>

        <div className="relative z-10 h-full flex flex-col p-6 pointer-events-none justify-between">
            <div className="flex flex-col">
                <div className="flex items-center gap-2 mb-1.5">
                   <Target className="w-3.5 h-3.5 text-green-500" />
                   <span className="text-[11px] text-green-500 uppercase font-black tracking-widest font-display">{t.target_multiplier}</span>
                </div>
                <div className="flex items-center gap-2 text-[11px] font-medium text-zinc-500 border-l-2 border-zinc-800 pl-4 transition-all">
                    {loading ? <span className="animate-pulse">{t.analyzing}</span> : prediction ? <span className="text-zinc-200">{t.signal_acquired}</span> : t.waiting}
                </div>
            </div>

            <div className="flex-1 flex flex-col items-center justify-center">
                 <div className="relative flex items-baseline justify-center w-full">
                     <span 
                       dir="ltr"
                       className={`font-display text-[6.5rem] font-bold tracking-tighter transition-all duration-300 ${
                         prediction 
                           ? 'text-transparent bg-clip-text bg-gradient-to-b from-white via-green-100 to-green-500 drop-shadow-[0_0_30px_rgba(34,197,94,0.5)]' 
                           : loading ? 'text-zinc-700' : 'text-zinc-800'
                       }`}
                     >
                        {displayMultiplier}
                     </span>
                     <span className={`text-4xl font-bold ml-2 -mb-2 font-display ${prediction ? 'text-green-500' : 'text-zinc-800'}`}>x</span>
                 </div>

                 <div className="h-8 mt-2 flex items-center justify-center">
                    {loading && (
                      <div className="flex items-center gap-3 bg-black/50 px-5 py-2 rounded-full border border-white/5 backdrop-blur-md">
                        <div className="w-3 h-3 border-2 border-green-500 border-t-transparent rounded-full animate-spin"></div>
                        <span className="text-[10px] text-green-500 font-mono tracking-widest uppercase font-bold">{t.calculating}</span>
                      </div>
                    )}
                    {prediction && (
                      <div className="flex items-center gap-2 px-4 py-1.5 rounded-full bg-zinc-900/80 border border-green-500/20 text-green-400 font-mono text-[9px] uppercase font-black tracking-widest shadow-lg">
                         <Clock className="w-3 h-3" />
                         {prediction.timestamp}
                      </div>
                    )}
                 </div>
            </div>
        </div>
      </div>

      <div className="grid grid-cols-3 gap-3 mb-6 shrink-0">
         {[
           { label: t.confidence, icon: Activity, value: prediction ? `${prediction.confidence}%` : "-", color: "text-green-500" },
           { label: t.safe_exit, icon: ShieldCheck, value: prediction ? `${prediction.safeCashOut.toFixed(2)}x` : "-", color: "text-yellow-500" },
           { label: t.signal, icon: BarChart2, value: prediction ? t.verified : "-", color: "text-blue-500" }
         ].map((item, i) => (
            <div key={i} className="bg-zinc-900/30 border border-zinc-800/50 p-4 rounded-2xl flex flex-col items-center justify-center backdrop-blur-md transition-all hover:bg-zinc-900/50">
                <span className="text-[10px] uppercase text-zinc-500 font-black mb-2 tracking-widest font-display">{item.label}</span>
                <item.icon className={`w-5 h-5 mb-2 ${prediction ? item.color : 'text-zinc-800'}`} />
                <span className={`text-[12px] font-mono font-black ${prediction ? 'text-zinc-100' : 'text-zinc-700'}`}>{item.value}</span>
            </div>
         ))}
      </div>

      <div className="mb-6 shrink-0">
        <button
          onClick={generatePrediction}
          disabled={loading || cooldown}
          className="relative w-full h-16 rounded-2xl bg-white hover:bg-zinc-100 active:scale-[0.98] transition-all text-black font-black text-sm uppercase tracking-widest shadow-[0_15px_40px_rgba(255,255,255,0.15)] disabled:opacity-50 disabled:grayscale flex items-center justify-center gap-3 font-display overflow-hidden group"
        >
          <div className="absolute inset-0 bg-gradient-to-r from-transparent via-black/5 to-transparent -translate-x-full group-hover:translate-x-full transition-transform duration-1000"></div>
          {loading ? (
            <span className="animate-pulse font-mono tracking-tighter">{t.processing}</span>
          ) : cooldown ? (
            <div className="flex items-center gap-2">
               <Shield className="w-4 h-4 text-zinc-400" />
               <span className="text-zinc-500 font-mono tracking-widest">UPLINK COOLDOWN...</span>
            </div>
          ) : (
            <>
              <Zap className="w-5 h-5 fill-black" />
              <span>{t.get_prediction}</span>
            </>
          )}
        </button>
      </div>

      {history.length > 0 && (
        <div className="animate-in slide-in-from-bottom-5 duration-700 fade-in shrink-0">
          <div className="flex items-center gap-3 mb-4 px-1">
