          ctx.moveTo(state.points[0].x, state.points[0].y);
          for (let i = 1; i < state.points.length; i++) {
              ctx.lineTo(state.points[i].x, state.points[i].y);
          }
          ctx.lineTo(currentX, currentY);
          ctx.strokeStyle = '#22c55e';
          ctx.lineWidth = 5;
          ctx.stroke();

          ctx.lineTo(currentX, h);
          ctx.lineTo(state.points[0].x, h);
          ctx.closePath();
          const gradient = ctx.createLinearGradient(0, currentY, 0, h);
          gradient.addColorStop(0, 'rgba(34, 197, 94, 0.3)');
          gradient.addColorStop(1, 'rgba(0, 0, 0, 0)');
          ctx.fillStyle = gradient;
          ctx.fill();
      }

      for (let i = particlesRef.current.length - 1; i >= 0; i--) {
          const p = particlesRef.current[i];
          p.x += p.vx; p.y += p.vy; p.life -= 0.025;
          if (p.life <= 0) { particlesRef.current.splice(i, 1); continue; }
          ctx.fillStyle = `${p.color}${p.life})`;
          ctx.beginPath(); ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2); ctx.fill();
      }

      if (state.status !== 'IDLE') {
          ctx.save();
          ctx.translate(currentX, currentY);
          ctx.fillStyle = '#22c55e';
          ctx.shadowBlur = 15;
          ctx.shadowColor = 'rgba(34, 197, 94, 0.6)';
          ctx.beginPath();
          ctx.moveTo(16, 0); ctx.lineTo(-14, -11); ctx.lineTo(-10, 0); ctx.lineTo(-14, 11);
          ctx.closePath(); ctx.fill();
          ctx.restore();
      }

      animationFrameId = requestAnimationFrame(render);
    };

    render(performance.now());
    return () => cancelAnimationFrame(animationFrameId);
  }, []);

  return (
    <div className="flex flex-col h-full px-5 pt-3 pb-8 overflow-y-auto custom-scrollbar">

      <div className="flex justify-between items-end mb-5 px-1 py-3 border-b border-zinc-900/50">
        <div className="flex flex-col gap-1">
           <span className="text-[10px] font-bold text-zinc-600 uppercase tracking-widest font-display">Data Stream</span>
           <div className="flex items-center gap-2">
              <div className="relative flex h-2 w-2">
                <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-500 opacity-75"></span>
                <span className="relative inline-flex rounded-full h-2 w-2 bg-green-500"></span>
              </div>
              <span className="text-xs font-mono text-green-500 font-black uppercase tracking-widest">{t.system_active}</span>
           </div>
        </div>

        <div className="flex items-center gap-2 bg-zinc-900/70 px-4 py-1.5 rounded-lg border border-zinc-800">
            <Database className="w-3.5 h-3.5 text-green-500/50" />
            <span className="text-[11px] font-mono text-zinc-300 tracking-wider">ID: {userId || 'GUEST'}</span>
        </div>
      </div>

      <div className="relative w-full aspect-[16/11] bg-zinc-950 border border-zinc-800 rounded-[2.5rem] p-1.5 mb-6 overflow-hidden shrink-0 shadow-2xl">
        <div className="absolute inset-0 rounded-[2.3rem] overflow-hidden bg-[#050505]">
             <canvas ref={canvasRef} className="w-full h-full block" />
             <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,transparent_0%,#000000_100%)] pointer-events-none"></div>
        </div>

        <div className="relative z-10 h-full flex flex-col p-6 pointer-events-none justify-between">
            <div className="flex flex-col">
                <div className="flex items-center gap-2 mb-1.5">
                   <Target className="w-4 h-4 text-green-500" />
                   <span className="text-[11px] text-green-500 uppercase font-black tracking-widest font-display">{t.target_multiplier}</span>
                </div>
                <div className="flex items-center gap-2 text-[11px] font-medium text-zinc-500 border-l-2 border-green-500/20 pl-4 transition-all">
                    {loading ? <span className="animate-pulse">{t.analyzing}</span> : prediction ? <span className="text-zinc-100 font-bold">{t.signal_acquired}</span> : <span className="text-zinc-600 italic">Uplink established...</span>}
                </div>
            </div>

            <div className="flex-1 flex flex-col items-center justify-center">
                 <div className="relative flex items-baseline justify-center w-full">
                     <span 
                       dir="ltr"
                       className={`font-display text-[7rem] font-bold tracking-tighter transition-all duration-300 ${
                         prediction 
                           ? 'text-transparent bg-clip-text bg-gradient-to-b from-white via-green-100 to-green-500 drop-shadow-[0_0_35px_rgba(34,197,94,0.55)]' 
                           : loading ? 'text-zinc-600' : 'text-zinc-800'
                       }`}
                     >
                        {displayMultiplier}
                     </span>
                     <span className={`text-4xl font-bold ml-2 -mb-2 font-display ${prediction ? 'text-green-500' : 'text-zinc-800'}`}>x</span>
                 </div>

                 <div className="h-8 mt-2 flex items-center justify-center">
                    {loading && (
                      <div className="flex items-center gap-3 bg-black/60 px-6 py-2 rounded-full border border-white/10 backdrop-blur-md">
                        <Wifi className="w-3.5 h-3.5 text-green-500 animate-pulse" />
                        <span className="text-[10px] text-green-500 font-mono tracking-widest uppercase font-black">FETCHING ODD...</span>
                      </div>
                    )}
                    {prediction && (
                      <div className="flex items-center gap-2 px-5 py-2 rounded-full bg-zinc-900/90 border border-green-500/30 text-green-400 font-mono text-[10px] uppercase font-black tracking-widest shadow-[0_0_15px_rgba(0,0,0,0.5)]">
                         <Clock className="w-3.5 h-3.5" />
                         {prediction.timestamp}
                      </div>
                    )}
                 </div>
            </div>
        </div>
      </div>

      <div className="grid grid-cols-3 gap-3 mb-6 shrink-0">
         {[
           { label: t.confidence, icon: Activity, value: prediction ? `${prediction.confidence}%` : "-", color: "text-green-500" },
           { label: t.safe_exit, icon: ShieldCheck, value: prediction ? `${prediction.safeCashOut.toFixed(2)}x` : "-", color: "text-yellow-500" },
           { label: t.signal, icon: BarChart2, value: prediction ? t.verified : "-", color: "text-blue-500" }
         ].map((item, i) => (
            <div key={i} className="bg-zinc-900/40 border border-zinc-800 p-4 rounded-2xl flex flex-col items-center justify-center backdrop-blur-md transition-all hover:bg-zinc-900/60 group/card">
                <span className="text-[10px] uppercase text-zinc-500 font-black mb-2 tracking-widest font-display">{item.label}</span>
                <item.icon className={`w-5 h-5 mb-2 transition-transform duration-300 group-hover/card:scale-110 ${prediction ? item.color : 'text-zinc-800'}`} />
                <span className={`text-[12px] font-mono font-black ${prediction ? 'text-zinc-50' : 'text-zinc-700'}`}>{item.value}</span>
            </div>
         ))}
      </div>

      <div className="mb-6 shrink-0">
        <button
          onClick={generatePrediction}
          disabled={loading || cooldown}
          className="relative w-full h-16 rounded-[1.5rem] bg-white hover:bg-zinc-100 active:scale-[0.98] transition-all text-black font-black text-sm uppercase tracking-widest shadow-[0_20px_45px_rgba(255,255,255,0.15)] disabled:opacity-50 disabled:grayscale flex items-center justify-center gap-3 font-display overflow-hidden group"
        >
          <div className="absolute inset-0 bg-gradient-to-r from-transparent via-black/5 to-transparent -translate-x-full group-hover:translate-x-full transition-transform duration-1000"></div>
          {loading ? (
            <span className="animate-pulse font-mono tracking-tighter">FETCHING DB UPLINK...</span>
          ) : cooldown ? (
            <div className="flex items-center gap-3">
               <div className="w-2 h-2 rounded-full bg-yellow-500 animate-pulse"></div>
               <span className="text-zinc-500 font-mono tracking-widest">COOLING DOWN...</span>
            </div>
          ) : (
            <>
              <Zap className="w-5 h-5 fill-black" />
              <span>{t.get_prediction}</span>
            </>
          )}
        </button>
      </div>

      {history.length > 0 && (
        <div className="animate-in slide-in-from-bottom-5 duration-700 fade-in shrink-0">
          <div className="flex items-center gap-3 mb-4 px-1">
             <div className="flex items-center gap-2">
                <History className="w-4 h-4 text-zinc-600" />
                <span className="text-[10px] font-black text-zinc-500 uppercase tracking-widest font-display">{t.prev_signals}</span>
             </div>
             <div className="h-px flex-1 bg-zinc-900/50"></div>
          </div>

          <div className="grid grid-cols-5 gap-2.5" dir="ltr">
            {history.slice(0, 5).map((item, idx) => (
               <div key={idx} className="flex flex-col items-center justify-center p-3 rounded-xl bg-zinc-900/50 border border-zinc-800/40 hover:bg-zinc-900 transition-all hover:-translate-y-0.5 shadow-sm">
                  <span className={`text-[11px] font-mono font-black ${item.multiplier >= 2.0 ? 'text-green-500' : 'text-blue-500'}`}>
                    {item.multiplier.toFixed(2)}x
                  </span>
                  <span className="text-[8px] text-zinc-700 font-mono mt-1 font-bold">{item.timestamp.split(' ')[2]}s</span>
               </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default InfoView;
